342→
343→      {/* Unassigned Parts */}
344→      <div className={styles.section}>
345→        <div className={styles.sectionHeaderRow}>
346→          <span className={styles.sectionTitle}>
347→            Unassigned Parts
348→          </span>
349→          <span className={styles.count}>{unassignedParts.length}</span>
350→        </div>
351→
352→        <div className={styles.layerList}>
353→          {renderPartTree(unassignedParts, 0)}
354→        </div>
355→      </div>
356→
357→      {/* Sheets */}
358→      <div className={styles.section}>
359→        <div className={styles.sectionHeaderRow}>
360→          <span className={styles.sectionTitle}>Sheets</span>
361→          <span className={styles.count}>{sheets.length}</span>
362→          <button className={styles.addBtn} onClick={handleAddSheet} aria-label="Add Sheet" title="Add Sheet">+</button>
363→        </div>
364→
365→        <div className={styles.layerList}>
366→          {sheets.map((sheet) => {
367→            const isActive = workspaceMode === 'sheet' && activeSheetId === sheet.id;
368→            return (
369→              <div
370→                key={sheet.id}
371→                className={`${styles.layerItem} ${isActive ? styles.layerItemActive : ''}`}
372→                onClick={() => handleSelectSheet(sheet.id)}
373→                role="button"
374→                tabIndex={0}
375→                onKeyDown={(e) => {
376→                  if (e.key === 'Enter' || e.key === ' ') {
377→                    e.preventDefault();
