392→                    onClick={(e) => handleDeleteSheet(e, sheet.id)}
393→                    aria-label="Delete Sheet"
394→                    title="Delete Sheet"
395→                  >
396→                    <TrashIcon />
397→                  </button>
398→                </div>
399→              </div>
400→            );
401→          })}
402→        </div>
403→      </div>
404→    </div>
